def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 2, -1):
                for b in range(1, a + 4):
                    exponent = ((ratio / a) ** 4 + np.log1p(b))
                    trig = np.sin(ratio * b / (a + 0.5))
                    priority += (exponent * trig) / (a + b)
            priority += np.tanh(np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 2
            if i % 2 == 0:
                for c in range(1, 6):
                    priority += np.sin(c * ratio) * np.log1p(bin_cap / (item + c))
        elif 5 < ratio <= 8:
            s = 0
            for d in range(1, 10):
                val = ((ratio - 5) ** d) / (d * 1.5)
                s += val * np.cos(ratio * d * 0.7)
            priority = s * np.exp(-ratio / 7) + np.tanh(ratio) * 5
            for e in range(1, 5):
                priority += np.cos(ratio * e * (i + 1) / 4) * (np.log1p(e + ratio)) / (e + 1)
        elif 2 <= ratio <= 5:
            s1, s2 = 0, 0
            for f in range(1, 15):
                s1 += ((ratio - 2) ** f) / (f * 2.1) * np.sin(f * ratio / 3)
            for g in range(1, 7):
                s2 += ((5 - ratio) ** g) / (g * 1.2) * np.cos(g * ratio)
            priority = (s1 - s2) * np.tanh(2.5 - ratio) + np.log1p(bin_cap) * 3
            if bin_cap < item * 0.9:
                priority += np.sqrt(item / (bin_cap + 0.7)) * 3.8
            else:
                priority -= np.exp(-0.5 * ratio)
        elif 0.5 <= ratio < 2:
            s = 0
            for h in range(1, 20):
                s += ((2 - ratio) ** h) / (h ** 2 + 1) * np.sin(h * ratio * 1.3)
            if i % 4 == 1:
                priority = s + np.cos(ratio * i) * 2 + np.exp(-ratio) * 2.5
            else:
                priority = s - np.sin(ratio * i) * 2 + np.log1p(item / bin_cap)
            for j in range(1, 5):
                priority += ((ratio - 0.5) ** j) / (j + 0.5) * np.sin(j * ratio * (i + 2))
        elif 0.2 <= ratio < 0.5:
            p = 0
            for k in range(1, 12):
                alpha = ((0.5 - ratio) ** k) / (k * 3.7) * np.cos(k * ratio * 3)
                p += alpha
            priority = p * np.tanh(bin_cap / (item + 0.3)) * 1.8
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + ratio)
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for l in range(1, 6):
                priority += ((0.5 - ratio) ** l) * np.sin(l * item * 0.8) * 0.5
        elif 0.05 <= ratio < 0.2:
            q = 0
            for m in range(1, 15):
                beta = ((0.2 - ratio) ** m) / (m * 2) * np.cos(m * ratio * 4.2)
                q += beta
            priority = q + 1 / (bin_cap + 2)
            if int(item * 1.7) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.8
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 3.8
            else:
                priority -= np.exp(-ratio * 1.8) * 3.5
            for n in range(1, 8):
                priority += ((0.2 - ratio) ** n) / (n * 4) * np.cos(item * n * 0.9)
        else:
            r = 0
            for o in range(1, 12):
                r += ((0.05 - ratio) ** o) / (o * 6) * np.sin(o * item * 0.85)
            priority = r + 3 / (bin_cap + 2.5)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4.2
            if bin_cap < item * 0.07:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for p in range(1, 10):
                priority += ((0.05 - ratio) ** p) / (p * 8) * np.cos(item * p * 0.75)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx_offset in range(1, 5):
            if (i + idx_offset) % 4 == 0:
                priority += np.sin(ratio * (i + idx_offset) * 1.2) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx_offset) * 1.2) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        for z in range(1, 3):
            if (i * z + int(item)) % 5 == 0:
                priority += np.tanh(ratio * z * 0.8) * 1.1
            else:
                priority -= np.exp(-ratio * z) * 1.1
        priorities[i] = priority
    return priorities
